@staticmethod
def resolve_order(_root, info: ResolveInfo, *, external_reference=None, id=None):
    validate_one_of_args_is_in_query(
        "id", id, "external_reference", external_reference
    )
    database_connection_name = get_database_connection_name(info.context)
    if not id:
        requester = get_user_or_app_from_context(info.context)
        permissions = [OrderPermissions.MANAGE_ORDERS]
        if not has_one_of_permissions(requester, permissions):
            raise PermissionDenied(permissions=permissions)
        try:
            id = ext_ref_to_global_id_or_error(
                models.Order, external_reference, database_connection_name
            )
        except ValidationError:
            return None
    _, id = from_global_id_or_error(id, Order)
    return resolve_order(info, id)

def resolve_order(info, id):
    if id is None:
        return None
    try:
        id = UUID(id)
        lookup = Q(id=id)
    except ValueError:
        lookup = Q(number=id) & Q(use_old_id=True)
    database_connection_name = get_database_connection_name(info.context)
    order = models.Order.objects.using(database_connection_name).filter(lookup).first()
    if not order:
        return None
    return SyncWebhookControlContext(node=order, allow_sync_webhooks=True)
